import { PreventableEvent } from '../common/preventable-event';
/**
 * Provides arguments for the `excelExport` event.
 */
export class ExcelExportEvent extends PreventableEvent {
    workbook;
    /**
     * @hidden
     */
    constructor(workbook) {
        super();
        this.workbook = workbook;
    }
}
